UPDATE $$T_SCHEMA_NAME.ALV_FACT_LEC_LINES_LIS_HST SET NT_IND_SK=0 WHERE RPT_DT_SK =$$RPT_DT_SK;
UPDATE $$T_SCHEMA_NAME.ALV_FACT_LEC_LINES_LIS_HST FROM ( SELECT B.TRANS_ID_SK AS TRANS_ID_SK_X,B.RPT_DT_SK AS RPT_DT_SK_X, B.SRC_SK AS SRC_SK_X,A.NT_IND_SK FROM DW_ALV_TBLSV.ALV_FACT_SVC_ACTY A INNER JOIN $$T_SCHEMA_NAME.ALV_FACT_LEC_LINES_LIS_HST B ON B.WTN = A.WTN WHERE RPT_DT_SK =$$RPT_DT_SK AND (A.METRIC_TYPE_SK=1 OR A.LINE_PDCT_ACTY_SK=8) AND A.NT_IND_SK<>0 AND A.FTTP_IND_SK=1 QUALIFY ROW_NUMBER() OVER( PARTITION BY B.TRANS_ID_SK,B.RPT_DT_SK,B.SRC_SK ORDER BY B.TRANS_ID_SK,B.RPT_DT_SK,B.SRC_SK DESC ) = 1) I SET NT_IND_SK=I.NT_IND_SK WHERE TRANS_ID_SK=I.TRANS_ID_SK_X AND RPT_DT_SK=I.RPT_DT_SK_X AND SRC_SK=I.SRC_SK_X AND RPT_DT_SK =$$RPT_DT_SK;
UPDATE $$T_SCHEMA_NAME.ALV_FACT_LEC_LINES_LIS_HST FROM ( SELECT B.TRANS_ID_SK AS TRANS_ID_SK_X, B.RPT_DT_SK AS RPT_DT_SK_X,B.SRC_SK AS SRC_SK_X,1 AS NT_IND_SK FROM $$T_SCHEMA_NAME1.ALV_LTR0_LTR1_S A INNER JOIN $$T_SCHEMA_NAME.ALV_FACT_LEC_LINES_LIS_HST B ON B.WTN = A.WTN WHERE RPT_DT_SK = $$RPT_DT_SK AND B.FTTP_COPPER_IND_SK=0 QUALIFY ROW_NUMBER() OVER( PARTITION BY B.TRANS_ID_SK,B.RPT_DT_SK,B.SRC_SK ORDER BY B.TRANS_ID_SK,B.RPT_DT_SK,B.SRC_SK DESC ) = 1) I SET NT_IND_SK=I.NT_IND_SK WHERE TRANS_ID_SK=I.TRANS_ID_SK_X AND RPT_DT_SK=I.RPT_DT_SK_X AND SRC_SK=I.SRC_SK_X AND RPT_DT_SK =$$RPT_DT_SK;
UPDATE $$T_SCHEMA_NAME.ALV_FACT_LEC_LINES_LIS_HST FROM ( SELECT B.TRANS_ID_SK AS TRANS_ID_SK_X, B.RPT_DT_SK AS RPT_DT_SK_X,B.SRC_SK AS SRC_SK_X,2 AS NT_IND_SK FROM $$T_SCHEMA_NAME1.ALV_LTR0_LTR1_S A INNER JOIN $$T_SCHEMA_NAME.ALV_FACT_LEC_LINES_LIS_HST B ON B.WTN = A.WTN WHERE RPT_DT_SK = $$RPT_DT_SK AND FTTP_COPPER_IND_SK=0 AND B.NT_IND_SK=1 AND A.LTR1_TARGET_CUST_CONTACT_DATE IS NOT NULL QUALIFY ROW_NUMBER() OVER( PARTITION BY B.TRANS_ID_SK,B.RPT_DT_SK,B.SRC_SK ORDER BY B.TRANS_ID_SK,B.RPT_DT_SK,B.SRC_SK DESC ) = 1) I SET NT_IND_SK=I.NT_IND_SK WHERE TRANS_ID_SK=I.TRANS_ID_SK_X AND RPT_DT_SK=I.RPT_DT_SK_X AND SRC_SK=I.SRC_SK_X AND RPT_DT_SK =$$RPT_DT_SK;
UPDATE $$T_SCHEMA_NAME.ALV_FACT_LEC_LINES_LIS_HST FROM ( SELECT A.TRANS_ID_SK AS TRANS_ID_SK_X, A.SRC_SK AS SRC_SK_X, A.RPT_DT_SK AS RPT_DT_SK_X, B.ACCT_NO FROM $$T_SCHEMA_NAME.ALV_FACT_LEC_LINES_LIS_HST A INNER JOIN OS_BBB_TBLSV.FIN_HST_AUTO_PAY B ON A.BTN||A.CUST_CD = B.ACCT_NO WHERE RPT_DT_SK=$$RPT_DT_SK QUALIFY ROW_NUMBER() OVER( PARTITION BY A.TRANS_ID_SK,A.SRC_SK,A.RPT_DT_SK ORDER BY A.TRANS_ID_SK,A.SRC_SK,A.RPT_DT_SK, B.ACCT_NO DESC ) = 1 )I SET AUTO_PAY_IND_SK = 1 WHERE TRANS_ID_SK = I.TRANS_ID_SK_X AND SRC_SK= I.SRC_SK_X AND RPT_DT_SK = I.RPT_DT_SK_X AND RPT_DT_SK =$$RPT_DT_SK;
UPDATE $$T_SCHEMA_NAME.ALV_FACT_LEC_LINES_LIS_HST FROM ( SELECT A.TRANS_ID_SK AS TRANS_ID_SK_X, A.SRC_SK AS SRC_SK_X, A.RPT_DT_SK AS RPT_DT_SK_X, CASE WHEN ST_CD IN ('NJ', 'PA', 'DE','PC','PG','PQ') THEN '102' WHEN ST_CD IN ('NY', 'CT', 'MA', 'RI') THEN '103' ELSE '101' END AS SRC_SYS_SK_X, CASE WHEN ST_CD IN ('PC' ,'PQ', 'PG' ) THEN 'PA' WHEN ST_CD IN ('VC' ,'VQ', 'VG' ) THEN 'VA' ELSE ST_CD END AS ALV_ST_CD_X FROM $$T_SCHEMA_NAME.ALV_FACT_LEC_LINES_LIS_HST A WHERE RPT_DT_SK= $$RPT_DT_SK QUALIFY ROW_NUMBER() OVER( PARTITION BY A.TRANS_ID_SK,A.SRC_SK,A.RPT_DT_SK ORDER BY A.TRANS_ID_SK,A.SRC_SK,A.RPT_DT_SK DESC ) = 1 )I SET SRC_SYS_SK = SRC_SYS_SK_X,ALV_ST_CD=I.ALV_ST_CD_X WHERE TRANS_ID_SK = I.TRANS_ID_SK_X AND SRC_SK= I.SRC_SK_X AND RPT_DT_SK = I.RPT_DT_SK_X AND RPT_DT_SK =$$RPT_DT_SK;
UPDATE $$T_SCHEMA_NAME.ALV_FACT_LEC_LINES_LIS_HST FROM ( SELECT A.TRANS_ID_SK AS TRANS_ID_SK_X, A.SRC_SK AS SRC_SK_X, A.RPT_DT_SK AS RPT_DT_SK_X, B.FINC_LOB_CD_SK AS FINC_LOB_CD_SK_X FROM $$T_SCHEMA_NAME.ALV_FACT_LEC_LINES_LIS_HST A INNER JOIN DW_SSP_TBLSV.SSP_FINC_LOB_DIM B ON A.LOB = B.FINC_LOB_CD WHERE RPT_DT_SK= $$RPT_DT_SK QUALIFY ROW_NUMBER() OVER( PARTITION BY A.TRANS_ID_SK,A.SRC_SK,A.RPT_DT_SK ORDER BY A.TRANS_ID_SK,A.SRC_SK,A.RPT_DT_SK, B.FINC_LOB_CD_SK DESC ) = 1 )I SET FINC_LOB_CD_SK = FINC_LOB_CD_SK_X WHERE TRANS_ID_SK = I.TRANS_ID_SK_X AND SRC_SK= I.SRC_SK_X AND RPT_DT_SK = I.RPT_DT_SK_X AND RPT_DT_SK =$$RPT_DT_SK;
UPDATE $$T_SCHEMA_NAME.ALV_FACT_LEC_LINES_LIS_HST FROM ( SELECT A.TRANS_ID_SK AS TRANS_ID_SK_X, A.SRC_SK AS SRC_SK_X, A.RPT_DT_SK AS RPT_DT_SK_X, CASE WHEN A.BTN=A.WTN THEN 1 ELSE 2 END AS LINE_TYPE_SK_X FROM $$T_SCHEMA_NAME.ALV_FACT_LEC_LINES_LIS_HST A WHERE RPT_DT_SK=$$RPT_DT_SK QUALIFY ROW_NUMBER() OVER( PARTITION BY A.TRANS_ID_SK,A.SRC_SK,A.RPT_DT_SK ORDER BY A.TRANS_ID_SK,A.SRC_SK,A.RPT_DT_SK DESC ) = 1 )I SET LINE_TYPE_SK= LINE_TYPE_SK_X WHERE TRANS_ID_SK = I.TRANS_ID_SK_X AND SRC_SK= I.SRC_SK_X AND RPT_DT_SK = I.RPT_DT_SK_X AND RPT_DT_SK =$$RPT_DT_SK;
UPDATE $$T_SCHEMA_NAME.ALV_FACT_LEC_LINES_LIS_HST FROM ( SELECT A.TRANS_ID_SK AS TRANS_ID_SK_X, A.SRC_SK AS SRC_SK_X, A.RPT_DT_SK AS RPT_DT_SK_X, B.BNDL_SK AS BNDL_SK_X FROM $$T_SCHEMA_NAME.ALV_FACT_LEC_LINES_LIS_HST A INNER JOIN DW_ALV_TBLSV.ALV_DIM_BUS_BNDL B ON A.USOC = B.EAST_BNDL_ID WHERE RPT_DT_SK=$$RPT_DT_SK QUALIFY ROW_NUMBER() OVER( PARTITION BY A.TRANS_ID_SK,A.SRC_SK,A.RPT_DT_SK ORDER BY A.TRANS_ID_SK,A.SRC_SK,A.RPT_DT_SK, B.BNDL_SK DESC ) = 1 )I SET BNDL_SK = BNDL_SK_X,BNDL_NON_BNDL_SK=1 WHERE TRANS_ID_SK = I.TRANS_ID_SK_X AND SRC_SK= I.SRC_SK_X AND RPT_DT_SK = I.RPT_DT_SK_X AND RPT_DT_SK =$$RPT_DT_SK;
UPDATE $$T_SCHEMA_NAME.ALV_FACT_LEC_LINES_LIS_HST SET BNDL_NON_BNDL_SK=2 WHERE BNDL_NON_BNDL_SK=-99999 AND RPT_DT_SK=$$RPT_DT_SK;
UPDATE $$T_SCHEMA_NAME.ALV_FACT_LEC_LINES_LIS_HST FROM ( SELECT A.TRANS_ID_SK AS TRANS_ID_SK_X, A.SRC_SK AS SRC_SK_X, A.RPT_DT_SK AS RPT_DT_SK_X, C.DMA_SK AS DMA_SK_X FROM $$T_SCHEMA_NAME.ALV_FACT_LEC_LINES_LIS_HST A INNER JOIN CDI_CRM_TBLSV.NPANXX B ON SUBSTR(A.WTN,1,6) = B.NPANXX INNER JOIN DW_ALV_TBLSV.ALV_DIM_DMA C ON B.DMACD = C.DMA_CD WHERE RPT_DT_SK=$$RPT_DT_SK QUALIFY ROW_NUMBER() OVER( PARTITION BY A.TRANS_ID_SK,A.SRC_SK,A.RPT_DT_SK ORDER BY A.TRANS_ID_SK,A.SRC_SK,A.RPT_DT_SK, C.DMA_SK DESC ) = 1 )I SET DMA_SK = DMA_SK_X WHERE TRANS_ID_SK = I.TRANS_ID_SK_X AND SRC_SK= I.SRC_SK_X AND RPT_DT_SK = I.RPT_DT_SK_X AND RPT_DT_SK =$$RPT_DT_SK;
COLLECT STATS ON OS_ALV.ALV_FACT_LEC_LINES_LIS_HST PRIMARY INDEX ( TRANS_ID_SK ,RPT_DT_SK ,SRC_SK );
UPDATE $$T_SCHEMA_NAME.ALV_FACT_LEC_LINES_LIS_HST FROM ( SELECT A.TRANS_ID_SK AS TRANS_ID_SK_X,A.RPT_DT_SK AS RPT_DT_SK_X ,A.SRC_SK AS SRC_SK_X, B.ST_SK AS ST_SK_X FROM $$T_SCHEMA_NAME.ALV_FACT_LEC_LINES_LIS_HST A INNER JOIN DW_SSP_TBLSV.SSP_STATE_DIM B ON A.ALV_ST_CD=B.ST_CD QUALIFY ROW_NUMBER() OVER(PARTITION BY A.TRANS_ID_SK,A.RPT_DT_SK,A.SRC_SK ORDER BY A.TRANS_ID_SK,A.RPT_DT_SK,A.SRC_SK,B.ST_SK DESC ) = 1 )D SET ST_SK=ST_SK_X WHERE TRANS_ID_SK=D.TRANS_ID_SK_X AND RPT_DT_SK=D.RPT_DT_SK_X AND SRC_SK=D.SRC_SK_X ;

UPDATE $$S_SCHEMA_NAME.ALV_FACT_LEC_LINES_LIS_HST FROM ( SELECT A.RPT_DT_SK AS RPT_DT_SK_x , B.CLLI AS WRCNTR_CLLI_X , B.WRCNTR_SK AS WRCNTR_SK_X , B.CUST_ID_NO AS VISION_CUST_ID_NO_X , B.ACCT_NO AS VISION_ACCT_NO_X ,A.SRC_SK AS SRC_SK_X ,A.TRANS_ID_SK AS TRANS_ID_SK_X FROM $$S_SCHEMA_NAME.ALV_FACT_LEC_LINES_LIS_HST A INNER JOIN ( SELECT DISTINCT BTN,CUST_CD,CLLI,WRCNTR_SK,CUST_ID_NO,ACCT_NO FROM $$S_SCHEMA_NAME1.ALV_TRN_LIS_BTN_CC WHERE CUST_ID_NO <> -99999 AND BTN IS NOT NULL AND CUST_CD IS NOT NULL) B ON A.BTN=B.BTN AND A.CUST_CD = B.CUST_CD WHERE RPT_DT_SK = $$RPT_DT_SK AND ST_CD IN ('NY','PA','DE') AND A.BTN IS NOT NULL AND A.CUST_CD IS NOT NULL QUALIFY ROW_NUMBER() OVER( PARTITION BY A.TRANS_ID_SK,A.SRC_SK,A.RPT_DT_SK ORDER BY A.TRANS_ID_SK,A.SRC_SK,A.RPT_DT_SK, B.CLLI DESC ) = 1 )I SET VISION_CUST_ID_NO = I.VISION_CUST_ID_NO_X, VISION_ACCT_NO = I.VISION_ACCT_NO_X, WRCNTR_CLLI = I.WRCNTR_CLLI_X, WRCNTR_SK = I.WRCNTR_SK_X WHERE TRANS_ID_SK = I.TRANS_ID_SK_X AND SRC_SK= I.SRC_SK_X AND RPT_DT_SK = I.RPT_DT_SK_X;
UPDATE $$S_SCHEMA_NAME.ALV_FACT_LEC_LINES_LIS_HST FROM ( SELECT A.RPT_DT_SK AS RPT_DT_SK_x , B.CLLI AS WRCNTR_CLLI_X , B.WRCNTR_SK AS WRCNTR_SK_X , B.CUST_ID_NO AS VISION_CUST_ID_NO_X , B.ACCT_NO AS VISION_ACCT_NO_X ,A.SRC_SK AS SRC_SK_X ,A.TRANS_ID_SK AS TRANS_ID_SK_X FROM $$S_SCHEMA_NAME.ALV_FACT_LEC_LINES_LIS_HST A INNER JOIN ( SELECT DISTINCT BTN,CUST_CD,CLLI,WRCNTR_SK,CUST_ID_NO,ACCT_NO FROM $$S_SCHEMA_NAME1.ALV_TRN_LIS_BTN_CC WHERE CUST_ID_NO <> -99999 AND BTN IS NOT NULL AND CUST_CD IS NOT NULL) B ON A.BTN=B.BTN AND A.CUST_CD = B.CUST_CD WHERE RPT_DT_SK = $$RPT_DT_SK AND ST_CD IN ('NJ','MA','RI') AND A.BTN IS NOT NULL AND A.CUST_CD IS NOT NULL QUALIFY ROW_NUMBER() OVER( PARTITION BY A.TRANS_ID_SK,A.SRC_SK,A.RPT_DT_SK ORDER BY A.TRANS_ID_SK,A.SRC_SK,A.RPT_DT_SK, B.CLLI DESC ) = 1 )I SET VISION_CUST_ID_NO = I.VISION_CUST_ID_NO_X, VISION_ACCT_NO = I.VISION_ACCT_NO_X, WRCNTR_CLLI = I.WRCNTR_CLLI_X, WRCNTR_SK = I.WRCNTR_SK_X WHERE TRANS_ID_SK = I.TRANS_ID_SK_X AND SRC_SK= I.SRC_SK_X AND RPT_DT_SK = I.RPT_DT_SK_X;
UPDATE $$S_SCHEMA_NAME.ALV_FACT_LEC_LINES_LIS_HST FROM ( SELECT A.RPT_DT_SK AS RPT_DT_SK_x , B.CLLI AS WRCNTR_CLLI_X , B.WRCNTR_SK AS WRCNTR_SK_X , B.CUST_ID_NO AS VISION_CUST_ID_NO_X , B.ACCT_NO AS VISION_ACCT_NO_X ,A.SRC_SK AS SRC_SK_X ,A.TRANS_ID_SK AS TRANS_ID_SK_X FROM $$S_SCHEMA_NAME.ALV_FACT_LEC_LINES_LIS_HST A INNER JOIN ( SELECT DISTINCT BTN,CUST_CD,CLLI,WRCNTR_SK,CUST_ID_NO,ACCT_NO FROM $$S_SCHEMA_NAME1.ALV_TRN_LIS_BTN_CC WHERE CUST_ID_NO <> -99999 AND BTN IS NOT NULL AND CUST_CD IS NOT NULL) B ON A.BTN=B.BTN AND A.CUST_CD = B.CUST_CD WHERE RPT_DT_SK = $$RPT_DT_SK AND ST_CD IN ('PG','VC','VG','PC','PQ','CT','NC','VQ') AND A.BTN IS NOT NULL AND A.CUST_CD IS NOT NULL QUALIFY ROW_NUMBER() OVER( PARTITION BY A.TRANS_ID_SK,A.SRC_SK,A.RPT_DT_SK ORDER BY A.TRANS_ID_SK,A.SRC_SK,A.RPT_DT_SK, B.CLLI DESC ) = 1 )I SET VISION_CUST_ID_NO = I.VISION_CUST_ID_NO_X, VISION_ACCT_NO = I.VISION_ACCT_NO_X, WRCNTR_CLLI = I.WRCNTR_CLLI_X, WRCNTR_SK = I.WRCNTR_SK_X WHERE TRANS_ID_SK = I.TRANS_ID_SK_X AND SRC_SK= I.SRC_SK_X AND RPT_DT_SK = I.RPT_DT_SK_X;

