UPDATE $$T_SCHEMA_NAME.ALV_FACT_LEC_LINES_LIS_HST SET ALV_USOC = NULL WHERE RPT_DT_SK=(SELECT RPT_DT_SK FROM $$T_SCHEMA_NAME.ALV_CTL_TGT_FACT WHERE STAT_CD='R');
UPDATE $$T_SCHEMA_NAME.ALV_FACT_LEC_LINES_LIS_HST SET ALV_METRIC_VAL=METRIC_VAL WHERE RPT_DT_SK=(SELECT RPT_DT_SK FROM $$T_SCHEMA_NAME.ALV_CTL_TGT_FACT WHERE STAT_CD='R');
