UPDATE $$T_SCHEMA_NAME.ALV_FACT_LEC_LINES_LIS_HST FROM ( SELECT A.TRANS_ID_SK AS TRANS_ID_SK_X,A.RPT_DT_SK AS RPT_DT_SK_X,A.SRC_SK AS SRC_SK_X , B.LGCY_USOC_TRNSL AS LGCY_USOC_TRNSL_X FROM $$T_SCHEMA_NAME.ALV_FACT_LEC_LINES_LIS_HST A,OS_ALV_ADMIN_TBLSV.ALV_TRN_CUR_USOC_TRANSL_RES_T B WHERE A.RPT_DT_SK=(SELECT RPT_DT_SK FROM $$T_SCHEMA_NAME.ALV_CTL_TGT_FACT WHERE STAT_CD='R') AND A.POF = B. PDCT_OFF_ID AND A.POE = B.PDCT_OFF_EQP_ID AND A.NKAU_CU_LN_F = B.LINE_CD AND A.SEGMENT_CD = B.SEG_CD AND A.SVC_TYP_CD = B.SVC_TYP_CD AND A.ST_CD = B.STATUS_CD AND A.ST_CD IN ('DC','MD','VA') AND A.SEGMENT_CD = 'RES') X SET ALV_USOC=LGCY_USOC_TRNSL_X WHERE TRANS_ID_SK=X.TRANS_ID_SK_X AND RPT_DT_SK=X.RPT_DT_SK_X AND SRC_SK=X.SRC_SK_X AND RPT_DT_SK=(SELECT RPT_DT_SK FROM $$T_SCHEMA_NAME.ALV_CTL_TGT_FACT WHERE STAT_CD='R');
