UPDATE $$T_SCHEMA_NAME.ALV_FACT_LEC_LINES_LIS_HST FROM ( SELECT TRANS_ID_SK AS TRANS_ID_SK_X,RPT_DT_SK AS RPT_DT_SK_X,SRC_SK AS SRC_SK_X,B.MULTIPLIER AS MULTIPLIER_X FROM $$T_SCHEMA_NAME.ALV_FACT_LEC_LINES_LIS_HST A INNER JOIN DW_ALV_TBLSV.ALV_REF_PRODMULTIPLIER B ON A.CLASSOFSVC ||'-'||A.ALV_USOC= B.CLASS_OF_SVC ||'-'||B.USOC WHERE ST_CD IN ('NY', 'CT','RI','MA') AND B.LOC='N' AND RPT_DT_SK=(SELECT RPT_DT_SK FROM $$T_SCHEMA_NAME.ALV_CTL_TGT_FACT WHERE STAT_CD='R') QUALIFY ROW_NUMBER() OVER(PARTITION BY A.TRANS_ID_SK,A.RPT_DT_SK,A.SRC_SK ORDER BY A.TRANS_ID_SK,A.RPT_DT_SK,A.SRC_SK DESC ) = 1) I SET ALV_METRIC_VAL=METRIC_VAL*I.MULTIPLIER_X WHERE TRANS_ID_SK=I.TRANS_ID_SK_X AND RPT_DT_SK=I.RPT_DT_SK_X AND SRC_SK=I.SRC_SK_X AND RPT_DT_SK=(SELECT RPT_DT_SK FROM $$T_SCHEMA_NAME.ALV_CTL_TGT_FACT WHERE STAT_CD='R');
UPDATE $$T_SCHEMA_NAME.ALV_FACT_LEC_LINES_LIS_HST FROM ( SELECT A.TRANS_ID_SK AS TRANS_ID_SK_X, A.SRC_SK AS SRC_SK_X, A.RPT_DT_SK AS RPT_DT_SK_X, CASE WHEN ST_CD IN ('NJ', 'PA','DE','PC','PG','PQ') THEN '102' WHEN ST_CD IN ('NY', 'CT', 'MA', 'RI') THEN '103' ELSE '101' END AS SRC_SYS_SK_X, CASE WHEN ST_CD IN ('PC' ,'PQ', 'PG' ) THEN 'PA' WHEN ST_CD IN ('VC' ,'VQ', 'VG' ) THEN 'VA' WHEN ST_CD IN ('CT' ) THEN 'NY' ELSE ST_CD END AS ALV_ST_CD_X FROM $$T_SCHEMA_NAME.ALV_FACT_LEC_LINES_LIS_HST A WHERE RPT_DT_SK=(SELECT RPT_DT_SK FROM $$T_SCHEMA_NAME.ALV_CTL_TGT_FACT WHERE STAT_CD='R') QUALIFY ROW_NUMBER() OVER( PARTITION BY A.TRANS_ID_SK,A.SRC_SK,A.RPT_DT_SK ORDER BY A.TRANS_ID_SK,A.SRC_SK,A.RPT_DT_SK DESC ) = 1 )I SET SRC_SYS_SK = SRC_SYS_SK_X,ALV_ST_CD=I.ALV_ST_CD_X WHERE TRANS_ID_SK = I.TRANS_ID_SK_X AND SRC_SK= I.SRC_SK_X AND RPT_DT_SK = I.RPT_DT_SK_X AND RPT_DT_SK=(SELECT RPT_DT_SK FROM $$T_SCHEMA_NAME.ALV_CTL_TGT_FACT WHERE STAT_CD='R');
UPDATE $$T_SCHEMA_NAME.ALV_FACT_LEC_LINES_LIS_HST FROM ( SELECT MAX(TRANS_ID_SK) AS TRANS_ID_SK_X,RPT_DT_SK AS RPT_DT_SK_X,SRC_SK AS SRC_SK_X,COUNT(1) AS COUNT_X FROM $$T_SCHEMA_NAME.ALV_FACT_LEC_LINES_LIS_HST A WHERE RPT_DT_SK=(SELECT RPT_DT_SK FROM $$T_SCHEMA_NAME.ALV_CTL_TGT_FACT WHERE STAT_CD='R') AND CLASSOFSVC ||'-'||ALV_USOC IN (SELECT ALISPRODUCT FROM DW_ALV_ADMIN_TBLSV.ALV_REF_TRN_PRODLOAD_S WHERE FIRST_LVL_HIER_GRP = 'TOTAL ACCESS LINES PLUS UNE PLATFORMS' AND FOURTH_LVL_HIER_GRP = 'CENTREX SERVICE') AND DATA_DATE= ( SEL MAX(DATA_DATE) FROM $$T_SCHEMA_NAME.ALV_FACT_LEC_LINES_LIS_HST WHERE ST_CD IN ('MD', 'DC', 'VA', 'VG', 'VC' ) AND RPT_DT_SK=(SELECT RPT_DT_SK FROM $$T_SCHEMA_NAME.ALV_CTL_TGT_FACT WHERE STAT_CD='R') ) AND ALV_ST_CD IN ('VA','MD','DC') AND LOB IN (01,03) GROUP BY RPT_DT_SK,SRC_SK,SNAPSHOT_DATE, DATA_DATE, SRC_S_DATA_DATE, SRC_N_DATA_DATE, ACCT_CD, SV_PNT_F, BTN, WTN, CUST_CD, ST_CD, LOB, CLASSOFSVC, USOC, SVC_ST_DT, VISION_CUST_ID_NO, VISION_ACCT_NO, WRCNTR_CLLI, WRCNTR_SK, ST_SK, FTTP_COPPER_IND_SK, NT_IND_SK, LOB_SK, ALV_ACCESS_LINE_IND_SK, SYS_ACCESS_LINE_IND_SK, MRKT_SGMNT_SK, SUB_ACCT_ESTABD_ST_SK, AUTO_PAY_IND_SK, SRC_SYS_SK, FINC_LOB_CD_SK, METRIC_VAL, LINE_TYPE_SK, DMA_SK, BNDL_SK, BNDL_NON_BNDL_SK, ALV_ST_CD HAVING COUNT(1)>1) I SET ALV_METRIC_VAL=0 WHERE TRANS_ID_SK=I.TRANS_ID_SK_X AND RPT_DT_SK=I.RPT_DT_SK_X AND SRC_SK=I.SRC_SK_X AND RPT_DT_SK=(SELECT RPT_DT_SK FROM $$T_SCHEMA_NAME.ALV_CTL_TGT_FACT WHERE STAT_CD='R');

DELETE FROM $$T_SCHEMA_NAME.ALV_FACT_LEC_LINES_LIS WHERE RPT_DT_SK IN ( select TM_SK from ( SELECT DAY_DT,TM_SK ,day_shrt_desC from mdr_dw_tblsv.time_dim WHERE (DAY_DT between (CURRENT_dATE - 180 ) and (current_date-8) and day_shrt_desC<>'WED' and day_dt<>fscl_mo_end_dt ) ) a);
DELETE FROM OS_ALV.ALV_LEC_LIS_MDV_HST WHERE CAST(ADD_DT AS DATE) IN ( select DAY_DT from ( SELECT DAY_DT,TM_SK ,day_shrt_desC,fscl_mo_end_dt from mdr_dw_tblsv.time_dim WHERE (DAY_DT between (CURRENT_dATE - 180 ) and (current_date-65) and day_shrt_desC<>'THU' AND day_dt<>CLNDR_MO_START_DT)) a);
DELETE FROM OS_ALV.ALV_LEC_LIS_HST WHERE CAST(ADD_DT AS DATE) IN ( select DAY_DT from ( SELECT DAY_DT,TM_SK ,day_shrt_desC,fscl_mo_end_dt from mdr_dw_tblsv.time_dim WHERE (DAY_DT between (CURRENT_dATE - 180 ) and (current_date-65) and day_shrt_desC<>'THU' AND day_dt<>CLNDR_MO_START_DT)) a);

