DELETE FROM $$T_SCHEMA_NAME.ALV_FACT_LEC_LINES_LIS WHERE RPT_DT_SK IN ( select TM_SK from ( SELECT DAY_DT,TM_SK ,day_shrt_desC from mdr_dw_tblsv.time_dim WHERE (DAY_DT between (CURRENT_dATE - 180 ) and (current_date-8) and day_shrt_desC<>'WED' and day_dt<>fscl_mo_end_dt ) ) a);
DELETE FROM OS_ALV.ALV_LEC_LIS_MDV_HST WHERE CAST(ADD_DT AS DATE) IN ( select DAY_DT from ( SELECT DAY_DT,TM_SK ,day_shrt_desC,fscl_mo_end_dt from mdr_dw_tblsv.time_dim WHERE (DAY_DT between (CURRENT_dATE - 180 ) and (current_date-65) and day_shrt_desC<>'THU' AND day_dt<>CLNDR_MO_START_DT)) a);
DELETE FROM OS_ALV.ALV_LEC_LIS_HST WHERE CAST(ADD_DT AS DATE) IN ( select DAY_DT from ( SELECT DAY_DT,TM_SK ,day_shrt_desC,fscl_mo_end_dt from mdr_dw_tblsv.time_dim WHERE (DAY_DT between (CURRENT_dATE - 180 ) and (current_date-65) and day_shrt_desC<>'THU' AND day_dt<>CLNDR_MO_START_DT)) a);
UPDATE OS_ALV.ALV_FACT_LEC_LINES_LIS_HST FROM ( SELECT A.TRANS_ID_SK AS TRANS_ID_SK_X,A.RPT_DT_SK AS RPT_DT_SK_X ,A.SRC_SK AS SRC_SK_X, B.BNDL_SK AS BNDL_NON_BNDL_SK_X FROM OS_ALV_TBLSV.ALV_FACT_LEC_LINES_LIS_HST A INNER JOIN (SELECT BNDL_SK,BTN,WTN,CUSTCODE FROM DW_ALV_TBLSV.ALV_FACT_SADATABTN_NSWP A INNER JOIN DW_ALV_TBLSV.ALV_DIM_BUS_BNDL B ON A.USOC=B.EAST_BNDL_ID AND REPORT_TRACKING_IND='Y' WHERE LOB = '03000' AND REGION_IND <> 'W' ) B ON A.BTN=B.BTN AND A.WTN IS NOT NULL AND B.WTN IS NOT NULL AND A.WTN <> '0000000000' AND B.WTN <> '0000000000' AND A.ALV_ACCESS_LINE_IND_SK=1 QUALIFY ROW_NUMBER() OVER(PARTITION BY A.TRANS_ID_SK,A.RPT_DT_SK,A.SRC_SK ORDER BY A.TRANS_ID_SK,A.RPT_DT_SK,A.SRC_SK,B.BNDL_SK DESC ) = 1 )D SET BNDL_NON_BNDL_SK=1 WHERE TRANS_ID_SK=D.TRANS_ID_SK_X AND RPT_DT_SK=D.RPT_DT_SK_X AND SRC_SK=D.SRC_SK_X and LOB='03' AND ALV_ACCESS_LINE_IND_SK=1;
UPDATE OS_ALV.ALV_FACT_LEC_LINES_LIS_HST FROM ( SELECT A.TRANS_ID_SK AS TRANS_ID_SK_X,A.RPT_DT_SK AS RPT_DT_SK_X ,A.SRC_SK AS SRC_SK_X, B.ST_SK AS ST_SK_X FROM OS_ALV_TBLSV.ALV_FACT_LEC_LINES_LIS_HST A INNER JOIN DW_SSP_TBLSV.SSP_STATE_DIM B ON A.ALV_ST_CD=B.ST_CD QUALIFY ROW_NUMBER() OVER(PARTITION BY A.TRANS_ID_SK,A.RPT_DT_SK,A.SRC_SK ORDER BY A.TRANS_ID_SK,A.RPT_DT_SK,A.SRC_SK,B.ST_SK DESC ) = 1 )D SET ST_SK=ST_SK_X WHERE TRANS_ID_SK=D.TRANS_ID_SK_X AND RPT_DT_SK=D.RPT_DT_SK_X AND SRC_SK=D.SRC_SK_X ;
UPDATE OS_ALV.ALV_FACT_LEC_LINES_LIS_HST SET ALV_ACCESS_LINE_IND_SK=0 WHERE ALV_ST_CD='VA' AND ST_SK=-99999;
UPDATE OS_ALV.ALV_FACT_LEC_LINES_LIS_HST SET ALV_ACCESS_LINE_IND_SK=0 WHERE ALV_ST_CD='PA' AND ST_SK=-99999;
UPDATE TGT FROM OS_ALV.ALV_FACT_LEC_LINES_LIS_HST TGT, (SELECT DISTINCT A.TRANS_ID_SK AS TRANS_ID_SK_X,A.RPT_DT_SK AS RPT_DT_SK_X,A.SRC_SK AS SRC_SK_X , A.BTN,B.PRODUCT,A.ST_CD,B.SERIES_CODE,B.GROUP_NAME FROM OS_ALV.ALV_FACT_LEC_LINES_LIS_HST A, OS_ALV_ADMIN_TBLSV.ALV_TRN_VFRAME_PROD_GRPS_N B WHERE TRIM(A.CLASSOFSVC)|| '-' ||TRIM(A.USOC) =TRIM(B.PRODUCT ) AND A.ST_CD IN ('CT', 'MA','NY', 'RI') AND COALESCE(WTN,'') <> '' AND WTN <> '0000000000' AND LOB = '01' AND A.ALV_ACCESS_LINE_IND_SK=1 AND B.GROUP_NAME = 'primaryResidence' AND A.RPT_DT_SK=(SELECT RPT_DT_SK FROM OS_ALV_TBLSV.ALV_CTL_TGT_FACT WHERE STAT_CD='R') ) SRC SET SERIES_CODE = SRC.SERIES_CODE ,GROUP_NAME = SRC.GROUP_NAME WHERE TGT.TRANS_ID_SK = SRC.TRANS_ID_SK_X AND TGT.RPT_DT_SK = SRC.RPT_DT_SK_X AND TGT.SRC_SK = SRC.SRC_SK_X AND TGT.BTN = SRC.BTN AND TGT.ST_CD = SRC.ST_CD AND TRIM(TGT.CLASSOFSVC)|| '-' ||TRIM(TGT.USOC) =TRIM(SRC.PRODUCT ) AND TGT.LOB = '01' AND TGT.ALV_ACCESS_LINE_IND_SK=1 AND RPT_DT_SK=(SELECT RPT_DT_SK FROM OS_ALV_TBLSV.ALV_CTL_TGT_FACT WHERE STAT_CD='R');
UPDATE TGT FROM OS_ALV.ALV_FACT_LEC_LINES_LIS_HST TGT, (SELECT DISTINCT A.TRANS_ID_SK AS TRANS_ID_SK_X,A.RPT_DT_SK AS RPT_DT_SK_X,A.SRC_SK AS SRC_SK_X , A.WTN,B.PRODUCT,A.ST_CD,B.SERIES_CODE,B.GROUP_NAME FROM OS_ALV.ALV_FACT_LEC_LINES_LIS_HST A, OS_ALV_ADMIN_TBLSV.ALV_TRN_VFRAME_PROD_GRPS_N B WHERE TRIM(A.CLASSOFSVC)|| '-' ||TRIM(A.USOC) =TRIM(B.PRODUCT ) AND A.ST_CD IN ('CT', 'MA','NY', 'RI') AND COALESCE(WTN,'') <> '' AND WTN <> '0000000000' AND LOB = '01' AND A.ALV_ACCESS_LINE_IND_SK=1 AND B.GROUP_NAME = 'secondaryResidence' AND A.RPT_DT_SK=(SELECT RPT_DT_SK FROM OS_ALV_TBLSV.ALV_CTL_TGT_FACT WHERE STAT_CD='R') ) SRC SET SERIES_CODE = SRC.SERIES_CODE ,GROUP_NAME = SRC.GROUP_NAME WHERE TGT.TRANS_ID_SK = SRC.TRANS_ID_SK_X AND TGT.RPT_DT_SK = SRC.RPT_DT_SK_X AND TGT.SRC_SK = SRC.SRC_SK_X AND TGT.WTN = SRC.WTN AND TGT.ST_CD = SRC.ST_CD AND TRIM(TGT.CLASSOFSVC)|| '-' ||TRIM(TGT.USOC) =TRIM(SRC.PRODUCT ) AND TGT.LOB = '01' AND TGT.ALV_ACCESS_LINE_IND_SK=1 AND RPT_DT_SK=(SELECT RPT_DT_SK FROM OS_ALV_TBLSV.ALV_CTL_TGT_FACT WHERE STAT_CD='R');
