UPDATE TGT FROM OS_ALV.ALV_FACT_LEC_LINES_LIS_HST TGT, (SELECT DISTINCT A.TRANS_ID_SK AS TRANS_ID_SK_X,A.RPT_DT_SK AS RPT_DT_SK_X,A.SRC_SK AS SRC_SK_X , A.BTN,B.PRODUCT,A.ST_CD,B.SERIES_CODE,B.GROUP_NAME FROM OS_ALV.ALV_FACT_LEC_LINES_LIS_HST A, OS_ALV_ADMIN_TBLSV.ALV_TRN_VFRAME_PROD_GRPS_P B WHERE TRIM(A.CLASSOFSVC)|| '-' ||TRIM(A.USOC) =TRIM(B.PRODUCT ) AND A.ST_CD IN ('PC', 'PG', 'PQ', 'VG', 'VC','VQ', 'NC') AND COALESCE(WTN,'') <> '' AND WTN <> '0000000000' AND LOB = '01' AND A.ALV_ACCESS_LINE_IND_SK=1 AND B.GROUP_NAME = 'primaryResidence' AND A.RPT_DT_SK=(SELECT RPT_DT_SK FROM OS_ALV_TBLSV.ALV_CTL_TGT_FACT WHERE STAT_CD='R') ) SRC SET SERIES_CODE = SRC.SERIES_CODE ,GROUP_NAME = SRC.GROUP_NAME WHERE TGT.TRANS_ID_SK = SRC.TRANS_ID_SK_X AND TGT.RPT_DT_SK = SRC.RPT_DT_SK_X AND TGT.SRC_SK = SRC.SRC_SK_X AND TGT.BTN = SRC.BTN AND TGT.ST_CD = SRC.ST_CD AND TRIM(TGT.CLASSOFSVC)|| '-' ||TRIM(TGT.USOC) =TRIM(SRC.PRODUCT) AND TGT.LOB = '01' AND TGT.ALV_ACCESS_LINE_IND_SK=1 AND RPT_DT_SK=(SELECT RPT_DT_SK FROM OS_ALV_TBLSV.ALV_CTL_TGT_FACT WHERE STAT_CD='R');
UPDATE TGT FROM OS_ALV.ALV_FACT_LEC_LINES_LIS_HST TGT, (SELECT DISTINCT A.TRANS_ID_SK AS TRANS_ID_SK_X,A.RPT_DT_SK AS RPT_DT_SK_X,A.SRC_SK AS SRC_SK_X , A.WTN,B.PRODUCT,A.ST_CD,B.SERIES_CODE,B.GROUP_NAME FROM OS_ALV.ALV_FACT_LEC_LINES_LIS_HST A, OS_ALV_ADMIN_TBLSV.ALV_TRN_VFRAME_PROD_GRPS_P B WHERE TRIM(A.CLASSOFSVC)|| '-' ||TRIM(A.USOC) =TRIM(B.PRODUCT ) AND A.ST_CD IN ('PC', 'PG', 'PQ', 'VG', 'VC','VQ', 'NC') AND COALESCE(WTN,'') <> '' AND WTN <> '0000000000' AND LOB = '01' AND A.ALV_ACCESS_LINE_IND_SK=1 AND B.GROUP_NAME = 'secondaryResidence' AND A.RPT_DT_SK=(SELECT RPT_DT_SK FROM OS_ALV_TBLSV.ALV_CTL_TGT_FACT WHERE STAT_CD='R') ) SRC SET SERIES_CODE = SRC.SERIES_CODE ,GROUP_NAME = SRC.GROUP_NAME WHERE TGT.TRANS_ID_SK = SRC.TRANS_ID_SK_X AND TGT.RPT_DT_SK = SRC.RPT_DT_SK_X AND TGT.SRC_SK = SRC.SRC_SK_X AND TGT.WTN = SRC.WTN AND TGT.ST_CD = SRC.ST_CD AND TRIM(TGT.CLASSOFSVC)|| '-' ||TRIM(TGT.USOC) =TRIM(SRC.PRODUCT ) AND TGT.LOB = '01' AND TGT.ALV_ACCESS_LINE_IND_SK=1 AND RPT_DT_SK=(SELECT RPT_DT_SK FROM OS_ALV_TBLSV.ALV_CTL_TGT_FACT WHERE STAT_CD='R');
UPDATE TGT FROM OS_ALV.ALV_FACT_LEC_LINES_LIS_HST TGT, (SELECT LIS.TRANS_ID_SK AS TRANS_ID_SK_X,LIS.RPT_DT_SK AS RPT_DT_SK_X,LIS.SRC_SK AS SRC_SK_X , A.WTN,LIS.ALV_ST_CD FROM DW_ALV_TBLSV.ALV_FACT_SVC_ACTY A, OS_ALV.ALV_FACT_LEC_LINES_LIS_HST LIS, DW_SSP_TBLSV.SSP_STATE_DIM S, MDR_DW_TBLSV.TIME_DIM T WHERE METRIC_TYPE_SK IN (1,2) AND A.WTN = LIS.WTN AND A.WTN <> '0000000000' AND A.SVC_ST_SK = S.ST_SK AND A.MDR_PDCT_CHG_DT_SK = T.TM_SK AND LOB_DESC = 'CON' AND A.LINE_TYPE_SK = 2 AND LIS.ALV_ACCESS_LINE_IND_SK=1 AND LIS.ALV_ST_CD IN ('NY', 'CT', 'RI', 'MA','DC', 'DE', 'MD','NC', 'NJ', 'PA', 'VA') AND LIS.RPT_DT_SK=(SELECT RPT_DT_SK FROM OS_ALV_TBLSV.ALV_CTL_TGT_FACT WHERE STAT_CD='R') QUALIFY ROW_NUMBER() OVER (PARTITION BY LIS.TRANS_ID_SK,LIS.RPT_DT_SK,LIS.SRC_SK,A.WTN, LIS.ALV_ST_CD ORDER BY t.DAY_DT DESC, A.METRIC_VAL DESC, A.METRIC_TYPE_SK ASC) =1) SRC SET ACTVT_LINE_TYPE_SK = 2 WHERE TGT.TRANS_ID_SK = SRC.TRANS_ID_SK_X AND TGT.RPT_DT_SK = SRC.RPT_DT_SK_X AND TGT.SRC_SK = SRC.SRC_SK_X AND TGT.WTN = SRC.WTN AND TGT.ALV_ST_CD = SRC.ALV_ST_CD AND TGT.LOB = '01' AND TGT.ALV_ACCESS_LINE_IND_SK=1 AND RPT_DT_SK=(SELECT RPT_DT_SK FROM OS_ALV_TBLSV.ALV_CTL_TGT_FACT WHERE STAT_CD='R');
UPDATE OS_ALV.ALV_FACT_LEC_LINES_LIS_HST SET DRV_LINE_TYPE_SK = -99999, DRV_ALV_METRIC_VAL = 0, DRV_ALV_ACCESS_LINE_IND_SK = 0 WHERE LOB = '01' AND RPT_DT_SK=(SELECT RPT_DT_SK FROM OS_ALV_TBLSV.ALV_CTL_TGT_FACT WHERE STAT_CD='R');
UPDATE OS_ALV.ALV_FACT_LEC_LINES_LIS_HST SET DRV_LINE_TYPE_SK = CASE WHEN GROUP_NAME = 'primaryResidence' AND LINE_TYPE_SK = 1 THEN 1 WHEN GROUP_NAME = 'secondaryResidence' THEN 2 ELSE -99999 END WHERE ALV_ST_CD IN ('NJ','PA','DE') AND LOB = '01' AND ALV_ACCESS_LINE_IND_SK=1 AND RPT_DT_SK=(SELECT RPT_DT_SK FROM OS_ALV_TBLSV.ALV_CTL_TGT_FACT WHERE STAT_CD='R');
UPDATE OS_ALV.ALV_FACT_LEC_LINES_LIS_HST SET DRV_LINE_TYPE_SK = CASE WHEN GROUP_NAME = 'secondaryResidence' OR LINE_TYPE_SK =2 OR ACTVT_LINE_TYPE_SK = 2 THEN 2 WHEN GROUP_NAME = 'primaryResidence' AND LINE_TYPE_SK = 1 THEN 1 ELSE -99999 END WHERE ALV_ST_CD IN ('NY','RI','MA') AND LOB = '01' AND ALV_ACCESS_LINE_IND_SK=1 AND RPT_DT_SK=(SELECT RPT_DT_SK FROM OS_ALV_TBLSV.ALV_CTL_TGT_FACT WHERE STAT_CD='R');
UPDATE OS_ALV.ALV_FACT_LEC_LINES_LIS_HST SET DRV_LINE_TYPE_SK = CASE WHEN GROUP_NAME = 'secondaryResidence' OR LINE_TYPE_SK =2 OR ACTVT_LINE_TYPE_SK = 2 THEN 2 WHEN GROUP_NAME = 'primaryResidence' OR LINE_TYPE_SK = 1 THEN 1 ELSE -99999 END WHERE ALV_ST_CD IN ('VA','DC','MD') AND LOB = '01' AND ALV_ACCESS_LINE_IND_SK=1 AND RPT_DT_SK=(SELECT RPT_DT_SK FROM OS_ALV_TBLSV.ALV_CTL_TGT_FACT WHERE STAT_CD='R');
UPDATE TGT FROM OS_ALV.ALV_FACT_LEC_LINES_LIS_HST TGT, (SELECT A.TRANS_ID_SK AS TRANS_ID_SK_X,A.RPT_DT_SK AS RPT_DT_SK_X,A.SRC_SK AS SRC_SK_X , A.DATA_DATE,A.WTN,A.ALV_ST_CD,A.DRV_LINE_TYPE_SK,SUM(A.DRV_ALV_METRIC_VALUE) AS ALV_LINE_CNT FROM ( SELECT * FROM ( SELECT A.*, CASE WHEN ALV_METRIC_VAL = 0 THEN METRIC_VAL ELSE ALV_METRIC_VAL END AS DRV_ALV_METRIC_VALUE FROM OS_ALV.ALV_FACT_LEC_LINES_LIS_HST A WHERE ALV_ST_CD IN ('NJ','PA','DE') AND LOB = '01' AND A.ALV_ACCESS_LINE_IND_SK=1 AND DRV_LINE_TYPE_SK > 0 AND A.RPT_DT_SK=(SELECT RPT_DT_SK FROM OS_ALV_TBLSV.ALV_CTL_TGT_FACT WHERE STAT_CD='R') ) A QUALIFY ROW_NUMBER() OVER (PARTITION BY WTN,ALV_ST_CD ORDER BY DRV_LINE_TYPE_SK DESC ) = 1 ) A GROUP BY 1,2,3,4,5,6,7) SRC SET DRV_ALV_METRIC_VAL = SRC.ALV_LINE_CNT WHERE TGT.TRANS_ID_SK = SRC.TRANS_ID_SK_X AND TGT.RPT_DT_SK = SRC.RPT_DT_SK_X AND TGT.SRC_SK = SRC.SRC_SK_X AND TGT.WTN = SRC.WTN AND TGT.DATA_DATE = SRC.DATA_DATE AND TGT.ALV_ST_CD = SRC.ALV_ST_CD AND TGT.DRV_LINE_TYPE_SK = SRC.DRV_LINE_TYPE_SK AND TGT.LOB = '01' AND TGT.ALV_ACCESS_LINE_IND_SK=1 AND RPT_DT_SK=(SELECT RPT_DT_SK FROM OS_ALV_TBLSV.ALV_CTL_TGT_FACT WHERE STAT_CD='R');
UPDATE TGT FROM OS_ALV.ALV_FACT_LEC_LINES_LIS_HST TGT, (SELECT A.TRANS_ID_SK AS TRANS_ID_SK_X,A.RPT_DT_SK AS RPT_DT_SK_X,A.SRC_SK AS SRC_SK_X , A.DATA_DATE,A.WTN,A.ALV_ST_CD, A.DRV_LINE_TYPE_SK ,SUM(A.DRV_ALV_METRIC_VALUE) AS ALV_LINE_CNT FROM ( SELECT * FROM ( SELECT A.*, CASE WHEN ALV_METRIC_VAL = 0 THEN METRIC_VAL ELSE ALV_METRIC_VAL END AS DRV_ALV_METRIC_VALUE FROM OS_ALV.ALV_FACT_LEC_LINES_LIS_HST A WHERE ALV_ST_CD IN ('NY','RI','MA') AND LOB = '01' AND A.ALV_ACCESS_LINE_IND_SK=1 AND DRV_LINE_TYPE_SK > 0 AND A.RPT_DT_SK=(SELECT RPT_DT_SK FROM OS_ALV_TBLSV.ALV_CTL_TGT_FACT WHERE STAT_CD='R') ) A QUALIFY ROW_NUMBER() OVER (PARTITION BY WTN,ALV_ST_CD ORDER BY DRV_LINE_TYPE_SK DESC ) = 1 ) A GROUP BY 1,2,3,4,5,6,7) SRC SET DRV_ALV_METRIC_VAL = SRC.ALV_LINE_CNT WHERE TGT.TRANS_ID_SK = SRC.TRANS_ID_SK_X AND TGT.RPT_DT_SK = SRC.RPT_DT_SK_X AND TGT.SRC_SK = SRC.SRC_SK_X AND TGT.WTN = SRC.WTN AND TGT.DATA_DATE = SRC.DATA_DATE AND TGT.ALV_ST_CD = SRC.ALV_ST_CD AND TGT.DRV_LINE_TYPE_SK = SRC.DRV_LINE_TYPE_SK AND TGT.LOB = '01' AND TGT.ALV_ACCESS_LINE_IND_SK=1 AND RPT_DT_SK=(SELECT RPT_DT_SK FROM OS_ALV_TBLSV.ALV_CTL_TGT_FACT WHERE STAT_CD='R');
UPDATE TGT FROM OS_ALV.ALV_FACT_LEC_LINES_LIS_HST TGT, ( SELECT A.TRANS_ID_SK_X,A.RPT_DT_SK_X,A.SRC_SK_X , A.DATA_DATE,A.WTN,A.ALV_ST_CD,A.DRV_LINE_TYPE_SK,A.ALV_LINE_CNT FROM ( SELECT A.TRANS_ID_SK AS TRANS_ID_SK_X,A.RPT_DT_SK AS RPT_DT_SK_X,A.SRC_SK AS SRC_SK_X , DATA_DATE,WTN,ALV_ST_CD, DRV_LINE_TYPE_SK ,SUM(DRV_ALV_METRIC_VALUE) AS ALV_LINE_CNT FROM ( SELECT A.* ,CASE WHEN ALV_METRIC_VAL = 0 THEN METRIC_VAL ELSE ALV_METRIC_VAL END AS DRV_ALV_METRIC_VALUE FROM OS_ALV.ALV_FACT_LEC_LINES_LIS_HST A WHERE ALV_ST_CD IN ('VA','DC','MD') AND LOB = '01' AND A.ALV_ACCESS_LINE_IND_SK=1 AND DRV_LINE_TYPE_SK > 0 AND A.RPT_DT_SK=(SELECT RPT_DT_SK FROM OS_ALV_TBLSV.ALV_CTL_TGT_FACT WHERE STAT_CD='R') ) A GROUP BY 1,2,3,4,5,6,7) A QUALIFY ROW_NUMBER() OVER (PARTITION BY TRANS_ID_SK_X,RPT_DT_SK_X,SRC_SK_X,WTN,DATA_DATE,ALV_ST_CD,DRV_LINE_TYPE_SK ORDER BY ALV_LINE_CNT DESC ) = 1)SRC SET DRV_ALV_METRIC_VAL = SRC.ALV_LINE_CNT WHERE TGT.TRANS_ID_SK = SRC.TRANS_ID_SK_X AND TGT.RPT_DT_SK = SRC.RPT_DT_SK_X AND TGT.SRC_SK = SRC.SRC_SK_X AND TGT.WTN = SRC.WTN AND TGT.DATA_DATE = SRC.DATA_DATE AND TGT.ALV_ST_CD = SRC.ALV_ST_CD AND TGT.DRV_LINE_TYPE_SK = SRC.DRV_LINE_TYPE_SK AND TGT.LOB = '01' AND TGT.ALV_ACCESS_LINE_IND_SK=1 AND RPT_DT_SK=(SELECT RPT_DT_SK FROM OS_ALV_TBLSV.ALV_CTL_TGT_FACT WHERE STAT_CD='R');
UPDATE TGT FROM OS_ALV.ALV_FACT_LEC_LINES_LIS_HST TGT, (SELECT A.TRANS_ID_SK AS TRANS_ID_SK_X,A.RPT_DT_SK AS RPT_DT_SK_X,A.SRC_SK AS SRC_SK_X , A.ST_CD, A.DRV_LINE_TYPE_SK FROM ( SELECT A.* FROM OS_ALV.ALV_FACT_LEC_LINES_LIS_HST A WHERE DRV_LINE_TYPE_SK <> -99999 AND LOB = '01' AND A.ALV_ACCESS_LINE_IND_SK=1 AND A.RPT_DT_SK=(SELECT RPT_DT_SK FROM OS_ALV_TBLSV.ALV_CTL_TGT_FACT WHERE STAT_CD='R') QUALIFY ROW_NUMBER() OVER (PARTITION BY TRANS_ID_SK,RPT_DT_SK,SRC_SK,WTN,ALV_ST_CD,DRV_LINE_TYPE_SK ORDER BY DRV_ALV_METRIC_VAL DESC ) = 1 ) A GROUP BY 1,2,3,4,5) SRC SET DRV_ALV_ACCESS_LINE_IND_SK = 1 WHERE TGT.TRANS_ID_SK = SRC.TRANS_ID_SK_X AND TGT.RPT_DT_SK = SRC.RPT_DT_SK_X AND TGT.SRC_SK = SRC.SRC_SK_X AND TGT.ST_CD = SRC.ST_CD AND TGT.DRV_LINE_TYPE_SK = SRC.DRV_LINE_TYPE_SK AND TGT.LOB = '01' AND TGT.ALV_ACCESS_LINE_IND_SK=1 AND RPT_DT_SK=(SELECT RPT_DT_SK FROM OS_ALV_TBLSV.ALV_CTL_TGT_FACT WHERE STAT_CD='R');
UPDATE OS_ALV.ALV_FACT_LEC_LINES_LIS_HST SET DRV_LINE_TYPE_SK = LINE_TYPE_SK, DRV_ALV_METRIC_VAL = ALV_METRIC_VAL, DRV_ALV_ACCESS_LINE_IND_SK = ALV_ACCESS_LINE_IND_SK WHERE (LOB <> '01' OR ST_CD IN ('CT','NC')) AND ALV_ACCESS_LINE_IND_SK=1 AND RPT_DT_SK=(SELECT RPT_DT_SK FROM OS_ALV_TBLSV.ALV_CTL_TGT_FACT WHERE STAT_CD='R');
UPDATE OS_ALV.ALV_FACT_LEC_LINES_LIS_HST SET DRV_ALV_ACCESS_LINE_IND_SK=0 WHERE ALV_ST_CD='VA' AND ST_SK=-99999 AND RPT_DT_SK=(SELECT RPT_DT_SK FROM OS_ALV_TBLSV.ALV_CTL_TGT_FACT WHERE STAT_CD='R');
UPDATE OS_ALV.ALV_FACT_LEC_LINES_LIS_HST SET DRV_ALV_ACCESS_LINE_IND_SK=0 WHERE ALV_ST_CD='PA' AND ST_SK=-99999 AND RPT_DT_SK=(SELECT RPT_DT_SK FROM OS_ALV_TBLSV.ALV_CTL_TGT_FACT WHERE STAT_CD='R');
